if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const records = $input.all().map(function(i) { return i.json; });
const wins = records.filter(function(r) { return r.decision_outcome === 'WIN'; });
const losses = records.filter(function(r) { return r.decision_outcome === 'LOSS'; });

const prompt = [
  'WIN/LOSS PATTERN ANALYSIS for Georgetown Defense Analytics (GDA)',
  '',
  'Analyze the following bid decision history and identify patterns.',
  '',
  '=== WIN/LOSS RECORDS (' + records.length + ' total) ===',
  records.map(function(r) {
    return r.decision_outcome + ' | ' + (r.opportunity_title || '') + ' | ' + (r.agency || '') + ' | $' + (r.contract_value || 0) + ' | Pwin: ' + (r.pwin_at_submission || 'N/A') + '% | Strengths: ' + (r.strengths || []).join(', ') + ' | Weaknesses: ' + (r.weaknesses || []).join(', ') + ' | Winner: ' + (r.winner || 'N/A');
  }).join('\n'),
  '',
  'Return ONLY valid JSON:',
  '{',
  '  "overall_win_rate": 0,',
  '  "win_patterns": ["pattern descriptions - what we do well"],',
  '  "loss_patterns": ["pattern descriptions - recurring weaknesses"],',
  '  "agency_performance": [{"agency": "name", "wins": 0, "losses": 0, "insight": "details"}],',
  '  "naics_performance": [{"naics": "code", "wins": 0, "losses": 0, "insight": "details"}],',
  '  "competitor_insights": [{"competitor": "name", "times_faced": 0, "wins_against": 0, "strategy_notes": ""}],',
  '  "price_analysis": {"avg_price_delta_wins": "X%", "avg_price_delta_losses": "X%", "insight": ""},',
  '  "recommendations": ["specific actionable recommendations"],',
  '  "pwin_calibration": {"avg_pwin_wins": 0, "avg_pwin_losses": 0, "calibration_note": ""},',
  '  "generated_at": "' + new Date().toISOString() + '"',
  '}'
].join('\n');

return [{ json: { prompt, record_count: records.length, win_count: wins.length, loss_count: losses.length } }];

var item = $input.first().json;
// Handle direct HTTP response from Anthropic API
var data = '';
if (item.content && Array.isArray(item.content)) {
  data = item.content.filter(function(c) { return c.type === 'text'; }).map(function(c) { return c.text; }).join('');
} else if (item.output) {
  data = item.output;
} else {
  data = JSON.stringify(item);
}
var start = data.indexOf('{');
var end = data.lastIndexOf('}');
var parsed = {};
try {
  if (start !== -1 && end !== -1) parsed = JSON.parse(data.substring(start, end + 1));
  else parsed = { error: 'No JSON found', raw: data.substring(0, 200) };
} catch(e) {
  try {
    var repaired = data.substring(start, end + 1).replace(/[\u2018\u2019]/g, "'").replace(/[\u201C\u201D]/g, '"').replace(/,\s*}/g, '}').replace(/,\s*]/g, ']');
    parsed = JSON.parse(repaired);
  } catch(e2) { parsed = { error: 'Parse failed: ' + e2.message }; }
}
parsed.status = 'ok';
parsed.action = 'analyze';
return [{ json: parsed }];
